class Solution {
public:
    vector<int> smallestTrimmedNumbers(vector<string>& nums, vector<vector<int>>& queries) {
        vector<int> res;
        for (auto& q : queries) {
            int k = q[0], trim = q[1];
            vector<pair<string, int>> v;
            for (int i = 0; i < nums.size(); i++) {
                string s = nums[i].substr(nums[i].size() - trim);
                v.push_back({s, i});
            }
            sort(v.begin(), v.end());
            res.push_back(v[k - 1].second);
        }
        return res;
    }
};
